import os, sys, traceback
import hou

def _run():
    root = hou.getenv("NIMBUS_ROOT")
    if not root:
        prefs = hou.getenv("HOUDINI_USER_PREF_DIR") or ""
        raise RuntimeError(
            "NIMBUS_ROOT is not set.\n"
            "Add a Nimbus package JSON under:\n  {0}/packages/".format(prefs)
        )
    pyroot = os.path.normpath(os.path.join(root, "scripts", "python"))
    if pyroot not in sys.path:
        sys.path.insert(0, pyroot)
    fullname = "nimbus.nimbus_hip_open"
    if fullname in sys.modules:
        del sys.modules[fullname]
    ver_name = os.path.basename(os.path.normpath(root))
    src_py = os.path.normpath(os.path.join(root, "..", "sources", ver_name, "python", "nimbus", "nimbus_hip_open.py"))
    if os.path.isfile(src_py):
        import importlib.util
        spec = importlib.util.spec_from_file_location(fullname, src_py)
        mod = importlib.util.module_from_spec(spec)
        sys.modules[fullname] = mod
        spec.loader.exec_module(mod)
        for name in ("_show_dialog", "show_dialog", "main"):
            fn = getattr(mod, name, None)
            if callable(fn):
                fn()
                return
    from nimbus.nimbus_menu_loader import launch
    launch("nimbus_hip_open", ("_show_dialog", "show_dialog", "main"))

try:
    _run()
except Exception:
    hou.ui.displayMessage("Nimbus Hip Open launch error:\n" + traceback.format_exc())

